const body = $input.first().json.body || $input.first().json;

const activityAtom = {
  user_id: body.user_id || 'unknown',
  name: body.name || 'Unknown User',
  email: body.email || '',
  company: body.company || 'Unknown Company',
  company_size: body.company_size || 'unknown',
  event_type: body.event || body.event_type || 'unknown',
  feature: body.feature || 'unknown',
  session_mins: body.session_duration_mins || 0,
  teammates_invited: body.teammates_invited || 0,
  api_calls_today: body.api_calls_today || 0,
  plan: body.plan || 'free_trial',
  source: body.source || 'unknown',
  phone: body.phone || '',
  call_consent: body.call_consent || false,
  email_consent: body.email_consent || true,
  processed_at: new Date().toISOString()
};

const ttlDays = 14;
const deleteAfter = new Date();
deleteAfter.setDate(deleteAfter.getDate() + ttlDays);
activityAtom.delete_after = deleteAfter.toISOString();
activityAtom.status = 'NEW';
activityAtom.email_status = 'NONE';
activityAtom.call_status = 'NOT_TRIGGERED';
activityAtom.demo_booked = false;

return [{ json: activityAtom }];

const groqResponse = $input.first().json;
const rawText = groqResponse.choices[0].message.content;
let classification;
try {
  classification = JSON.parse(rawText.replace(/```json|```/g, '').trim());
} catch(e) {
  classification = { tier: 'EXPLORER', intent_score: 10, reasoning: 'Parse Error' };
}
const userData = $('2. Save User Profile').first().json;
return [{ json: { ...userData, ...classification } }];

const groqResponse = $input.first().json;
const rawText = groqResponse.choices[0].message.content;
let emailDraft;
try {
  emailDraft = JSON.parse(rawText.replace(/```json|```/g, '').trim());
} catch(e) {
  emailDraft = { subject: 'Follow up', body: 'Hi', sales_contact_note: 'Error' };
}
const combinedData = $('4. Parse Intent').first().json;
return [{ json: { ...combinedData, email_draft: emailDraft } }];

const data = $input.first().json;
const score = data.intent_score;
const debateLog = [
  `Agent 1 → Event captured`,
  `Agent 2 → Classified: ${data.tier} (Score: ${score})`,
  `Agent 3 → Email drafted`,
  `Agent 7 → Decision: ${score >= 80 ? 'HOT LEAD - Slack + Email' : 'WARM LEAD - Email only'}`
];
return [{ json: { ...data, debate_log: debateLog, status: score >= 80 ? 'HOT_LEAD' : 'WARM_LEAD' } }];
